import"https://cdn.tailwindcss.com";async function a(){const t=localStorage.getItem("token"),e=await(await fetch("/api/admin/settings",{headers:{Authorization:`Bearer ${t}`}})).json();e&&(document.getElementById("businessName").value=e.name||"",document.getElementById("businessDescription").value=e.description||"",document.getElementById("businessPhone").value=e.telephone||"",document.getElementById("businessServiceAreas").value=e.service_areas?e.service_areas.join(", "):"",document.getElementById("businessHours").value="",document.getElementById("businessAddress").value=e.address||"",document.getElementById("businessWechat").value=e.wechat||"",document.getElementById("businessLicense").value=e.license||"",document.getElementById("businessPromises").value="")}document.getElementById("settingsForm").addEventListener("submit",async t=>{t.preventDefault();const n=localStorage.getItem("token"),e={name:document.getElementById("businessName").value,description:document.getElementById("businessDescription").value,telephone:document.getElementById("businessPhone").value,service_areas:document.getElementById("businessServiceAreas").value.split(/[,，]/).map(s=>s.trim()).filter(s=>s),address:document.getElementById("businessAddress").value,license:document.getElementById("businessLicense").value,wechat:document.getElementById("businessWechat").value};await fetch("/api/admin/settings",{method:"PUT",headers:{Authorization:`Bearer ${n}`,"Content-Type":"application/json"},body:JSON.stringify(e)}),alert("设置已保存")});a();
